+    /// Handle Anthropic Messages API (Claude Code compatible)
+    fn handleAnthropicMessages(self: *Self, stream: std.net.Stream, method: []const u8, body: []const u8) !void {
+        // Only accept POST
+        if (!std.mem.eql(u8, method, "POST")) {
+            try self.sendAnthropicError(stream, 405, "method_not_allowed", "Method not allowed");
+            stream.close();
+            return;
+        }
+
+        // Parse JSON request
+        const parsed = std.json.parseFromSlice(AnthropicRequest, self.allocator, body, .{
+            .ignore_unknown_fields = true,
+        }) catch {
+            try self.sendAnthropicError(stream, 400, "invalid_request_error", "Invalid JSON");
+            stream.close();
+            return;
+        };
+        defer parsed.deinit();
+
+        const anthro_req = parsed.value;
+
+        // Build prompt from Anthropic format
+        // Anthropic has system prompt separate from messages
+        var prompt_builder: std.ArrayListUnmanaged(u8) = .{};
+        errdefer prompt_builder.deinit(self.allocator);
+
+        var system_prompt_len: u32 = 0;
+
+        // Add system prompt if present
+        if (anthro_req.system) |sys| {
+            try prompt_builder.appendSlice(self.allocator, "<|im_start|>system\n");
+            try prompt_builder.appendSlice(self.allocator, sys);
+            try prompt_builder.appendSlice(self.allocator, "<|im_end|>\n");
+            system_prompt_len = @intCast(prompt_builder.items.len);
+        }
+
+        // Add messages (Anthropic only has user/assistant, no system in messages)
+        for (anthro_req.messages) |msg| {
+            if (std.mem.eql(u8, msg.role, "user")) {
+                try prompt_builder.appendSlice(self.allocator, "<|im_start|>user\n");
+                try prompt_builder.appendSlice(self.allocator, msg.content);
+                try prompt_builder.appendSlice(self.allocator, "<|im_end|>\n");
+            } else if (std.mem.eql(u8, msg.role, "assistant")) {
+                try prompt_builder.appendSlice(self.allocator, "<|im_start|>assistant\n");
+                try prompt_builder.appendSlice(self.allocator, msg.content);
+                try prompt_builder.appendSlice(self.allocator, "<|im_end|>\n");
+            }
+        }
+        // Add assistant start for generation
+        try prompt_builder.appendSlice(self.allocator, "<|im_start|>assistant\n");
+
+        const max_tokens = anthro_req.max_tokens;
+
+        // Check queue capacity
+        self.queue_mutex.lock();
+        const queue_len = self.request_queue.items.len;
+        const max_queue = self.config.max_concurrent * 2;
+        self.queue_mutex.unlock();
+
+        if (queue_len >= max_queue) {
+            prompt_builder.deinit(self.allocator);
+            try self.sendAnthropicError(stream, 529, "overloaded_error", "Server busy - queue full");
+            stream.close();
+            return;
+        }
+
+        // Create owned copy of prompt for the queue
+        const prompt_owned = try self.allocator.dupe(u8, prompt_builder.items);
+        prompt_builder.deinit(self.allocator);
+
+        // Queue the request
+        const request_id = self.next_request_id.fetchAdd(1, .monotonic);
+
+        self.queue_mutex.lock();
+        self.request_queue.append(self.allocator, .{
+            .id = request_id,
+            .stream = stream,
+            .cell_id = null,
+            .prompt = prompt_owned,
+            .system_prompt_len = system_prompt_len,
+            .max_tokens = max_tokens,
+            .submitted_at = std.time.milliTimestamp(),
+            .api_format = .anthropic,
+        }) catch {
+            self.queue_mutex.unlock();
+            self.allocator.free(prompt_owned);
+            try self.sendAnthropicError(stream, 500, "api_error", "Failed to queue request");
+            stream.close();
+            return;
+        };
+        self.queue_mutex.unlock();
+
+        logger.info("Queued Anthropic request {}: {} messages, max_tokens={}", .{ request_id, anthro_req.messages.len, max_tokens });
+        // Response will be sent by generationLoop when complete
+    }
