+    /// Build Anthropic Messages API response format
+    fn buildAnthropicResponse(self: *Self, content: []const u8, completion_tokens: u32, prompt_len: usize) ![]u8 {
+        // Escape content for JSON
+        var escaped: std.ArrayListUnmanaged(u8) = .{};
+        defer escaped.deinit(self.allocator);
+
+        for (content) |ch| {
+            switch (ch) {
+                '"' => try escaped.appendSlice(self.allocator, "\\\""),
+                '\\' => try escaped.appendSlice(self.allocator, "\\\\"),
+                '\n' => try escaped.appendSlice(self.allocator, "\\n"),
+                '\r' => try escaped.appendSlice(self.allocator, "\\r"),
+                '\t' => try escaped.appendSlice(self.allocator, "\\t"),
+                else => {
+                    if (ch < 0x20) {
+                        var buf: [6]u8 = undefined;
+                        const len = std.fmt.bufPrint(&buf, "\\u{x:0>4}", .{ch}) catch continue;
+                        try escaped.appendSlice(self.allocator, len);
+                    } else {
+                        try escaped.append(self.allocator, ch);
+                    }
+                },
+            }
+        }
+
+        // Calculate token counts
+        const input_tokens: u32 = @intCast(prompt_len / 4);
+
+        // Generate a unique message ID
+        const timestamp = std.time.timestamp();
+
+        return try std.fmt.allocPrint(self.allocator,
+            \\{{"id":"msg_{d}","type":"message","role":"assistant","content":[{{"type":"text","text":"{s}"}}],"model":"{s}","stop_reason":"end_turn","stop_sequence":null,"usage":{{"input_tokens":{d},"output_tokens":{d}}}}}
+        , .{
+            timestamp,
+            escaped.items,
+            self.model_name,
+            input_tokens,
+            completion_tokens,
+        });
+    }
+
+    /// Send Anthropic-format error response
+    fn sendAnthropicError(self: *Self, stream: std.net.Stream, status: u16, error_type: []const u8, message: []const u8) !void {
+        var buffer: [512]u8 = undefined;
+        const body = try std.fmt.bufPrint(&buffer,
+            \\{{"type":"error","error":{{"type":"{s}","message":"{s}"}}}}
+        , .{ error_type, message });
+
+        try self.sendResponse(stream, status, body);
+    }
